25	export function normalizeModelSlug(
26	  model: string | null | undefined,
27	  provider: ProviderKind = "codex",
28	): ModelSlug | null {
29	  if (typeof model !== "string") {
30	    return null;
31	  }
32	
33	  const trimmed = model.trim();
34	  if (!trimmed) {
35	    return null;
36	  }
37	
38	  const aliases = MODEL_SLUG_ALIASES_BY_PROVIDER[provider] as Record<string, ModelSlug>;
39	  const aliased = aliases[trimmed];
40	  return typeof aliased === "string" ? aliased : (trimmed as ModelSlug);
41	}
42	
43	export function resolveModelSlug(
44	  model: string | null | undefined,
45	  provider: ProviderKind = "codex",
46	): ModelSlug {
47	  const normalized = normalizeModelSlug(model, provider);
48	  if (!normalized) {
49	    return getDefaultModel(provider);
50	  }
51	
52	  return MODEL_SLUG_SET_BY_PROVIDER[provider].has(normalized)
53	    ? normalized
54	    : getDefaultModel(provider);
55	}
56	
57	export function resolveModelSlugForProvider(
58	  provider: ProviderKind,
59	  model: string | null | undefined,
60	): ModelSlug {
61	  return resolveModelSlug(model, provider);
62	}
