336	                              <span className="size-3.5 shrink-0" aria-hidden="true" />
337	                            )}
338	                            <span className="truncate">{option.label}</span>
339	                          </div>
340	                        </SelectItem>
341	                      ))}
342	                    </SelectPopup>
343	                  </Select>
344	                  <span className="text-xs text-muted-foreground">
345	                    {APP_SERVICE_TIER_OPTIONS.find((option) => option.value === codexServiceTier)
346	                      ?.description ?? "Use Codex defaults without forcing a service tier."}
347	                  </span>
348	                </label>
349	
350	                {MODEL_PROVIDER_SETTINGS.map((providerSettings) => {
351	                  const provider = providerSettings.provider;
352	                  const customModels = getCustomModelsForProvider(settings, provider);
353	                  const customModelInput = customModelInputByProvider[provider];
354	                  const customModelError = customModelErrorByProvider[provider] ?? null;
355	                  return (
356	                    <div
357	                      key={provider}
358	                      className="rounded-xl border border-border bg-background/50 p-4"
