373	                            className="block flex-1 space-y-1"
374	                          >
375	                            <span className="text-xs font-medium text-foreground">
376	                              Custom model slug
377	                            </span>
378	                            <Input
379	                              id={`custom-model-slug-${provider}`}
380	                              value={customModelInput}
381	                              onChange={(event) => {
382	                                const value = event.target.value;
383	                                setCustomModelInputByProvider((existing) => ({
384	                                  ...existing,
385	                                  [provider]: value,
386	                                }));
387	                                if (customModelError) {
388	                                  setCustomModelErrorByProvider((existing) => ({
389	                                    ...existing,
390	                                    [provider]: null,
391	                                  }));
392	                                }
393	                              }}
394	                              onKeyDown={(event) => {
395	                                if (event.key !== "Enter") return;
396	                                event.preventDefault();
