import { useCallback, useSyncExternalStore } from "react";
import { getTheme, listThemes, type Theme } from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:custom-theme";
const DEFAULT_THEME_ID = "t3-dark";

let listeners: Array<() => void> = [];
let lastSnapshot: Theme | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getStoredId(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw && listThemes().some((t) => t.id === raw)) return raw;
  return DEFAULT_THEME_ID;
}

function applyTheme(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Toggle Tailwind dark variant
  document.documentElement.classList.toggle("dark", theme.isDark);

  // Apply core identity CSS custom properties inline so they override the
  // stylesheet :root block while still letting derived variables (--muted,
  // --border, etc.) be supplied by index.css via the .dark class.
  const s = document.documentElement.style;
  s.setProperty("--background", theme.colors.background);
  s.setProperty("--foreground", theme.colors.foreground);
  s.setProperty("--primary", theme.colors.accent);
  s.setProperty("--ring", theme.colors.accent);
  s.setProperty("--sidebar-background", theme.colors.sidebar);
  s.setProperty("--editor-background", theme.colors.editor);
  s.setProperty("--terminal-background", theme.colors.terminal);
  s.setProperty("--status-bar-background", theme.colors.statusBar);
  s.setProperty("--font-size-base", `${theme.fontSize}px`);
  document.body.style.fontFamily = theme.fontFamily;

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash of wrong theme
applyTheme(getTheme(getStoredId()));

function getSnapshot(): Theme {
  const theme = getTheme(getStoredId());

  if (lastSnapshot && lastSnapshot.id === theme.id) {
    return lastSnapshot;
  }

  lastSnapshot = theme;
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for theme changes made in other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getTheme(getStoredId()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const theme = useSyncExternalStore(subscribe, getSnapshot);

  const resolvedTheme: "light" | "dark" = theme.isDark ? "dark" : "light";

  const setTheme = useCallback((id: string) => {
    const next = getTheme(id);
    localStorage.setItem(STORAGE_KEY, next.id);
    applyTheme(next, true);
    emitChange();
  }, []);

  const availableThemes = listThemes();

  return { theme, setTheme, availableThemes, resolvedTheme } as const;
}

