import { useTheme } from "../hooks/useTheme";
import type { Theme } from "@t3tools/shared/themes";

function ThemeSwatch({ theme }: { theme: Theme }) {
  return (
    <div
      aria-hidden="true"
      className="relative h-16 w-full overflow-hidden rounded-md"
      style={{ background: theme.colors.background }}
    >
      {/* Sidebar strip */}
      <div
        className="absolute inset-y-0 left-0 w-6"
        style={{ background: theme.colors.sidebar }}
      />
      {/* Accent band across the bottom */}
      <div
        className="absolute inset-x-0 bottom-0 h-1.5"
        style={{ background: theme.colors.statusBar }}
      />
      {/* Fake content lines */}
      <div className="absolute left-8 right-2 top-2.5 space-y-1.5">
        <div
          className="h-1.5 w-3/4 rounded-full opacity-30"
          style={{ background: theme.colors.foreground }}
        />
        <div
          className="h-1.5 w-1/2 rounded-full opacity-20"
          style={{ background: theme.colors.foreground }}
        />
        <div
          className="h-1.5 w-2/3 rounded-full opacity-15"
          style={{ background: theme.colors.foreground }}
        />
      </div>
      {/* Accent dot */}
      <div
        className="absolute right-2 top-2.5 h-2 w-2 rounded-full"
        style={{ background: theme.colors.accent }}
      />
    </div>
  );
}

/**
 * Renders a grid of clickable theme cards, each showing a colour-swatch
 * preview and the theme name. Integrates with useTheme() — no extra props
 * needed.
 */
export function ThemeSelector() {
  const { theme, setTheme, availableThemes } = useTheme();

  return (
    <div
      className="grid grid-cols-3 gap-3"
      role="radiogroup"
      aria-label="Color theme"
    >
      {availableThemes.map((t) => {
        const selected = theme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => setTheme(t.id)}
            className={`flex flex-col gap-2 rounded-lg border p-2 text-left transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring ${
              selected
                ? "border-primary/60 bg-primary/8"
                : "border-border bg-background hover:bg-accent"
            }`}
          >
            <ThemeSwatch theme={t} />
            <div className="flex items-center justify-between gap-1 px-0.5">
              <span
                className={`text-xs font-medium ${selected ? "text-foreground" : "text-muted-foreground"}`}
              >
                {t.name}
              </span>
              {selected && (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              )}
            </div>
          </button>
        );
      })}
    </div>
  );
}

